// User Management
package usermanager

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40032/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40032/idl"
	"github.com/arminguenther/xeruspower-go/v40032/usermgmt/user"
)

// Account information
type Account struct {
	Name string    // Account name
	Info user.Info // User information
}

// Base type of all account event
type AccountEvent interface {
	userevent.UserEvent
	Username() string // name of user which was affected
	isAccountEvent()
}

// This event is emitted after a new account with the
// provided username was added
type AccountAdded interface {
	AccountEvent
	isAccountAdded()
}

// This event is emitted after an account has been renamed
type AccountRenamed interface {
	AccountEvent
	NewUsername() string // new user name
	isAccountRenamed()
}

// This event is emitted after the account with
// the provided username has been removed
type AccountRemoved interface {
	AccountEvent
	isAccountRemoved()
}

// This event is emitted after the password for
// an account was changed
type PasswordChanged interface {
	AccountEvent
	isPasswordChanged()
}

// This event is emitted if the settings of an account
// as defined in usermgmt.UserInfo have changed
// (Note: we may add an indication what in the structure
// has changed or even split the event, if handling is difficult)
type AccountChanged interface {
	AccountEvent
	OldSettings() user.Info
	NewSettings() user.Info
	isAccountChanged()
}

const (
	ERR_USER_DOESNT_EXIST           int32 = 1  // A user with the given name does not exist
	ERR_USER_NOT_DELETABLE          int32 = 2  // The user is not deletable
	ERR_USER_ALREADY_EXISTS         int32 = 1  // A user with the given name already exists
	ERR_MAX_USERS_REACHED           int32 = 2  // Maximum number of users reached
	ERR_PASSWORD_TOO_SHORT_FOR_SNMP int32 = 3  // The password is too short to be used as SNMPv3 passphrase
	ERR_INVALID_VALUE               int32 = 4  // Invalid arguments
	ERR_PASSWORD_EMPTY              int32 = 5  // The password must not be empty
	ERR_PASSWORD_TOO_SHORT          int32 = 6  // The password is too short
	ERR_PASSWORD_TOO_LONG           int32 = 7  // The password is too long
	ERR_PASSWORD_CTRL_CHARS         int32 = 8  // The password must not contain control characters
	ERR_PASSWORD_NEED_LOWER         int32 = 9  // The password must contain at least one lower-case character
	ERR_PASSWORD_NEED_UPPER         int32 = 10 // The password must contain at least one upper-case character
	ERR_PASSWORD_NEED_NUMERIC       int32 = 11 // The password must contain at least one numeric character
	ERR_PASSWORD_NEED_SPECIAL       int32 = 12 // The password must contain at least one special character
	ERR_SSH_PUBKEY_DATA_TOO_LARGE   int32 = 14 // The ssh public key data is too large.
	ERR_SSH_PUBKEY_INVALID          int32 = 15 // The ssh public key is invalid.
	ERR_SSH_PUBKEY_NOT_SUPPORTED    int32 = 16 // The ssh public key is not supported.
	ERR_SSH_RSA_PUBKEY_TOO_SHORT    int32 = 17 // The ssh RSA public key is too short.
	ERR_USERNAME_INVALID            int32 = 18 // The user name contains one or more invalid character(s).
	ERR_NEW_USER_ALREADY_EXISTS     int32 = 19 // A user with the new (renamed) user name already exists
)

// User manager interface
type UserManager interface {
	idl.Object

	// Get a list of account names available on the system.
	//
	//	@return List of account names
	GetAccountNames(ctx context.Context) ([]string, error)

	// Create a new account.
	//
	//	@param username  New user name
	//	@param password  New password
	//
	//	@return  0 if OK
	//	@return  1 if a user with the given name already exists
	//	@return  2 if the maximum number of users is reached
	//	@return  3 SNMPv3 USM is activated for the user and the
	//	          password shall be used as auth passphrase. For this
	//	          case, the password is too short (must be at least 8
	//	          characters).
	//	@return  5 The password must not be empty.
	//	@return  6 The password is too short.
	//	@return  7 The password is too long.
	//	@return  8 The password must not contain control characters.
	//	@return  9 The password has to contain at least one lower case
	//	           character.
	//	@return 10 The password has to contain at least one upper case
	//	           character.
	//	@return 11 The password has to contain at least one numeric
	//	           character.
	//	@return 12 The password has to contain at least one printable
	//	           special character.
	//	@return 18 if the user name is invalid.
	CreateAccount(ctx context.Context, username string, password string) (int32, error)

	// Rename an account.
	//
	//	@param username     Current name of user
	//	@param newUsername  New name of the user
	//
	//	@return 0 if OK
	//	@return 1 if a user with the given name does not exist
	//	@return 19 if a user with the new name already exists
	RenameAccount(ctx context.Context, username string, newUsername string) (int32, error)

	// Deletes an account.
	//
	//	@param username  Name of user to delete
	//
	//	@return 0 if OK
	//	@return 1 if a user with the given name does not exist
	//	@return 2 if the user cannot be deleted
	DeleteAccount(ctx context.Context, username string) (int32, error)

	// Get information about all available user accounts.
	//
	//	@return List of accounts
	GetAllAccounts(ctx context.Context) ([]Account, error)

	// Create a new account with defined settings.
	//
	//	@param username  New user name
	//	@param password  New password
	//	@param info      New user information
	//
	//	@return  0 if OK
	//	@return  1 if a user with the given name already exists
	//	@return  2 if the maximum number of users is reached
	//	@return  3 SNMPv3 USM is activated for the user and the
	//	          password shall be used as auth passphrase. For this
	//	          case, the password is too short (must be at least 8
	//	          characters).
	//	@return  4 if any value in the user info is invalid.
	//	@return  5 The password must not be empty.
	//	@return  6 The password is too short.
	//	@return  7 The password is too long.
	//	@return  8 The password must not contain control characters.
	//	@return  9 The password has to contain at least one lower case
	//	           character.
	//	@return 10 The password has to contain at least one upper case
	//	           character.
	//	@return 11 The password has to contain at least one numeric
	//	           character.
	//	@return 12 The password has to contain at least one printable
	//	           special character.
	//	@return 14 The ssh public key data is too large.
	//	@return 15 The ssh public key is invalid.
	//	@return 16 The ssh public key is not supported.
	//	@return 17 The ssh RSA public key is too short.
	//	@return 18 if the user name is invalid.
	CreateAccountFull(ctx context.Context, username string, password string, info user.Info) (int32, error)

	// Get a list of accounts that have a given role.
	//
	//	@param roleName  Role name
	//
	//	@return List of accounts
	GetAccountsByRole(ctx context.Context, roleName string) ([]Account, error)

	// Get default user preferences.
	//
	//	@return Default user preferences.
	GetDefaultPreferences(ctx context.Context) (user.Preferences, error)

	// Set default user preferences.
	//
	//	@param prefs Default user preferences.
	//
	//	@return      0 if OK
	SetDefaultPreferences(ctx context.Context, prefs user.Preferences) (int32, error)
}
